import type {
  VocabularyWordDto,
  VocabularyWordStatus,
  VocabularyWordStatusId,
} from '@soenglish/shared-types';
import { VOCABULARY_WORD_STATUS_IDS } from '@soenglish/shared-types';

export { VOCABULARY_WORD_STATUS_IDS };

/** Resolve catalog status id to legacy union (labels / filters). */
export function vocabularyStatusIdToLegacy(statusId: VocabularyWordStatusId): VocabularyWordStatus {
  switch (statusId) {
    case VOCABULARY_WORD_STATUS_IDS.new:
      return 'new';
    case VOCABULARY_WORD_STATUS_IDS.learning:
      return 'learning';
    case VOCABULARY_WORD_STATUS_IDS.known:
      return 'known';
    default:
      return 'new';
  }
}

export function legacyStatusToVocabularyStatusId(
  status: VocabularyWordStatus,
): VocabularyWordStatusId {
  switch (status) {
    case 'new':
      return VOCABULARY_WORD_STATUS_IDS.new;
    case 'learning':
      return VOCABULARY_WORD_STATUS_IDS.learning;
    case 'known':
      return VOCABULARY_WORD_STATUS_IDS.known;
    default:
      return VOCABULARY_WORD_STATUS_IDS.new;
  }
}

